// === 低功耗状态机接口 ===
#ifndef LOWPOWER_H
#define LOWPOWER_H

#include <stdint.h>
#include <stdbool.h>

/* 电源管理状态——越深的模式越省电，但唤醒越慢 */
typedef enum {
    LP_ACTIVE    = 0,  /* 全速运行，所有外设在线 */
    LP_IDLE      = 1,  /* SLEEP 模式，Cortex-M 停摆，外设仍在跑 */
    LP_DEEPSLEEP = 2,  /* DEEPSLEEP，关掉主振荡器，RTC/backup 还在 */
    LP_STOP      = 3,  /* STOP 模式，所有时钟停，仅保留部分 GPIO 唤醒 */
    LP_STANDBY   = 4,  /* STANDBY，最小漏电，唤醒后相当于复位 */
} lowpower_mode_t;

/* 功耗预算——每个模式允许的最大外设 */
typedef struct {
    uint32_t max_current_uA;  /* 目标最大电流 */
    lowpower_mode_t mode;    /* 能达到的最深模式 */
    uint32_t wake_time_us;   /* 预期唤醒时间 */
    bool     rtc_running;    /* RTC 是否可用 */
    bool     ram_retained;   /* RAM 内容是否保留 */
} lowpower_budget_t;

/* 初始化电源管理器 */
int  lowpower_init(void);

/* 选择模式——内部会根据外设活动自动约束最深模式 */
lowpower_mode_t lowpower_select(lowpower_mode_t requested);

/* 进入选定的睡眠模式——非返回调用 */
void lowpower_enter(lowpower_mode_t mode);

/* 唤醒后恢复外设——在 main() 入口处调用 */
void lowpower_restore_after_wakeup(void);

/* 查询当前电源状态 */
lowpower_budget_t lowpower_get_budget(void);

#endif

// === 架构说明 ===
// 应用层只调用 lowpower_enter(LP_DEEPSLEEP)
// 电源管理器在内部检查：
//   1. ADC 是否需要保持？→ 是则不能进 STOP
//   2. USB 是否需要保持？→ 是则不能进 DEEPSLEEP
//   3. 看门狗是否依赖时钟？→ 是则唤醒后必须重启 IWDG
// 最终选择安全的最深模式——应用开发者不需要知道这些细节。

/* === 进入 STOP2 模式：完整 HAL 实现 === */
/* 适用平台：STM32L4 系列（如 L432KC） */
/* 目标电流：~1μA（不含唤醒源漏电） */

#include "stm32l4xx_hal.h"

static volatile bool g_wakeup_from_stop = false;
static volatile uint32_t g_wakeup_source = 0;

/* 唤醒前必须做的准备——在调用 enter 前执行 */
void lowpower_prepare_enter_stop2(void)
{
    /* 1. 将所有不用的 GPIO 设为模拟输入，降低漏电 */
    __HAL_RCC_GPIOC_CLK_ENABLE();
    GPIOC->MODER = 0x00000000;  /* 全部置为模拟模式 */
    __HAL_RCC_GPIOC_CLK_DISABLE();

    /* 2. 将关键数据备份到备份域 SRAM */
    /* STM32L4 的 BKP SRAM 在 STOP 模式下由 VBAT 保持 */
    HAL_PWREx_EnableBkUpReg();          /* 打开备份寄存器电源 */
    HAL_PWREx_EnableSRAM2();            /* 使能 SRAM2（备份域） */
    Backup_SRAM[0] = system_state;      /* 保存系统状态 */

    /* 3. 配置唤醒 EXTI（如 PA0 = WKUP 引脚） */
    __HAL_RCC_SYSCFG_CLK_ENABLE();
    __HAL_PWR_VOLTAGESCALING_CONFIG(PWR_REGULATOR_VOLTAGE_SCALE3);
    /* SCALE3: 1.5V 内核，STOP2 模式下可保持，唤醒后不需重配 */

    /* 4. 清除所有挂起的中断标志——否则可能立即唤醒 */
    __HAL_PWR_CLEAR_WUF_FLAG();
}

/* 进入 STOP2 模式——调用后本函数不返回 */
void lowpower_enter_stop2(void)
{
    /* 关闭 Flash 预取指和延迟，降低功耗 */
    FLASH->ACR &= ~FLASH_ACR_PRFTEN;  /* 关闭预取指 */
    FLASH->ACR &= ~FLASH_ACR_LATENCY; /* 延迟 = 0 */

    /* 触发 STOP2 模式——内部执行 WFE 指令 */
    HAL_PWR_EnterSTOPMode(PWR_LOWPOWERREGULATOR_ON,
                          PWR_STOPENTRY_WFE);
    /* WFE: Wait For Event——等待中断或事件唤醒 */
    /* 代码不会执行到这里，唤醒后从 main() 恢复执行 */
}

/* 唤醒后恢复——在 main() 入口或 startup 中调用 */
void lowpower_restore_after_stop2(void)
{
    /* 判断是否从 STOP 唤醒 */
    if (__HAL_PWR_GET_FLAG(PWR_FLAG_SBF)) {
        g_wakeup_from_stop = true;
        __HAL_PWR_CLEAR_FLAG(PWR_FLAG_SBF);  /* 清除 STOP 标志 */
    }

    if (g_wakeup_from_stop) {
        /* 恢复 Flash 性能（唤醒后自动恢复 HSE，无需重配 PLL）*/
        FLASH->ACR = FLASH_ACR_PRFTEN | FLASH_ACR_LATENCY_1;

        /* 恢复外设时钟——HAL 在进入 STOP 前会自动恢复 HSI/HSE */
        __HAL_RCC_GPIOC_CLK_ENABLE();

        /* 从备份 SRAM 恢复状态 */
        system_state = Backup_SRAM[0];

        /* 重启看门狗——DEEPSLEEP/STOP 后 IWDG 可能已计数 */
        HAL_IWDG_Start(&hiwdg);
    }
}

/* 中断优先级建议（STM32 NVIC 配置） */
/* EXTI0（WKUP）: 优先级 0（最高）——必须最先响应 */
/* RTC_Alarm:     优先级 1——闹钟唤醒优先级略低 */
/* 其他外设:     优先级 2-15——这些在外设层可延迟处理 */

// === 低功耗调试 checklist 代码 ===
// 每个陷阱都对应一个可执行的诊断步骤

// === 陷阱 1：唤醒后没有清除中断标志，导致反复唤醒 ===
// 症状：进入 DEEPSLEEP 后电流正常，
//        但唤醒后 10ms 内又自动进入 DEEPSLEEP，
//        循环往复，平均电流从 5μA 飙到 500μA
void diagnose_spurious_wakeup(void)
{
    /* 检查 PWR 状态标志——是否连续被唤醒 */
    uint32_t flags = PWR->SR1;
    if (flags & PWR_SR1_WUFI) {
        /* Wake-up flag internal——内部唤醒源触发了 */
        /* 修复：清除所有 WUF 标志 */
        __HAL_PWR_CLEAR_WUF_FLAG();
    }
    if (flags & PWR_SR1_SB) {
        /* System Boot——确认是否真的从睡眠唤醒 */
        /* 如果是意外唤醒，检查是否有未屏蔽的中断 */
    }
}

// === 陷阱 2：PA0 内部上拉在睡眠模式下漏电 ===
// 症状：测量显示 50μA 静置电流，但所有外设都关了
// 修复：将 PA0（WKUP 引脚）配置为浮空输入而非上拉
void fix_wkup_leakage(void)
{
    __HAL_RCC_GPIOA_CLK_ENABLE();
    /* 进入睡眠前：PA0 设为模拟输入（最低漏电） */
    GPIOA->MODER &= ~(0x3 << 0);  /* bit[1:0] = 00 模拟 */
    GPIOA->ODR &= ~(1 << 0);      /* 清除输出数据 */
    /* 或者：如果需要检测 WKUP 引脚，设无上拉的输入模式 */
    // GPIOA->PUPDR &= ~(0x3 << 0); /* 清除上拉/下拉 */
    __HAL_RCC_GPIOA_CLK_DISABLE();
}

// === 陷阱 3：未关闭未使用的电源域 ===
// 症状：STM32L4 进入 STOP2 后电流 200μA，比手册高 200 倍
// 修复：检查 ADC 电源域和 DAC 电源域是否关闭
void check_unused_power_domains(void)
{
    /* 检查 PWR 电源域状态 */
    /* ADC 在 ADC 寄存器里，STOP2 下必须关闭 */
    __HAL_RCC_ADC_CLK_DISABLE();
    /* DAC 在 PWR_CR1 里有独立控制位 */
    // PWR_CR1 的 DAC1R1DI 位——如果不用 DAC 要清零
    /* 检查 ADC 是否真的关了——读回确认 */
    if (ADC1->CR & ADC_CR_ADEN) {
        /* 意外！ADC 还在使能状态 */
        /* 修复：先请求禁用，等 ready 位清除后再关时钟 */
        ADC1->CR &= ~ADC_CR_ADEN;
        while (ADC1->ISR & ADC_ISR_ADRY) {
            /* 等待 ADC 完全关闭 */
        }
    }
}

// === 陷阱 4：调试器（SWD）保持连接，阻止深度睡眠 ===
// 症状：在 IDE 中调试时测到低电流，脱离 IDE 后电流飙升
// 原因：部分调试器在连接状态下会阻止 MCU 进入 STOP/STANDBY
// 修复：编译 Release 版本并断开调试器测量
// 或者：使用 ST-LINK 的 FORCE_DEBUG=0 配置
void disable_debug_during_sleep(void)
{
    /* 某些芯片在 Debug 模式下会自动禁用部分睡眠模式 */
    /* STM32L4 在 DBGMCU->CR 中有相关控制位 */
    // DBGMCU->CR |= DBGMCU_CR_SLEEP_DBG;  /* 允许睡眠调试 */
    // 但如果不想在睡眠时调试，保持默认即可
    /* 最佳实践：永远在 Release + 无调试器连接下测量电流 */
}

// === 陷阱 5：复位后外设初始化的顺序错误 ===
// 症状：首次上电正常，复位后进入 STOP 电流异常
// 原因：HAL 库在 SystemClock_Config() 中重新开启了某些外设时钟
void fix_clock_restore_order(void)
{
    /* 唤醒后恢复顺序至关重要：*/
    /* 第 1 步：恢复 Flash 配置（降低延迟后再恢复 PLL） */
    FLASH->ACR = FLASH_ACR_LATENCY_1 | FLASH_ACR_PRFTEN;
    /* 第 2 步：恢复 PLL 和系统时钟（HAL 自动处理） */
    SystemClock_Config();
    /* 第 3 步：才重新使能外设时钟 */
    __HAL_RCC_USART1_CLK_ENABLE();
    __HAL_RCC_GPIOB_CLK_ENABLE();
    /* 错误顺序会导致外设时钟在 PLL 稳定前就开始运行，*/
    /* 产生额外的瞬态电流尖峰，累积起来显著增加功耗 */
}

// === 重构前：硬编码睡眠——处处重复 ===
// ❌ 每个场景都有自己的睡眠函数，代码重复，无法组合

void ble_sleep_mode(void)
{
    /* BLE 广播间隔睡眠 */
    __HAL_RCC_GPIOC_CLK_DISABLE();
    __HAL_RCC_ADC_CLK_DISABLE();
    HAL_PWREx_EnableSRAM2();
    __HAL_PWR_CLEAR_WUF_FLAG();
    HAL_PWR_EnterDEEPSLEEP_MODE();
    // 唤醒后... 重复恢复代码 30 行
    __HAL_RCC_GPIOC_CLK_ENABLE();
    __HAL_RCC_ADC_CLK_ENABLE();
    // 重启 BLE
    BLE_Reinit();
}

void sensor_sleep_mode(void)
{
    /* 传感器采样间隔睡眠 */
    __HAL_RCC_GPIOC_CLK_DISABLE();  /* 重复！和上面一样 */
    __HAL_RCC_ADC_CLK_DISABLE();    /* 重复！和上面一样 */
    HAL_PWREx_EnableSRAM2();        /* 重复！ */
    __HAL_RCC_TIM2_CLK_DISABLE();   /* 新增：TIM2 也要关 */
    __HAL_PWR_CLEAR_WUF_FLAG();
    HAL_PWR_EnterSTOP2_MODE();      /* 不同！用 STOP2 而非 DEEPSLEEP */
    // 唤醒后... 又是 30 行重复代码
    __HAL_RCC_GPIOC_CLK_ENABLE();
    __HAL_RCC_ADC_CLK_ENABLE();
    __HAL_RCC_TIM2_CLK_ENABLE();    /* 新增：TIM2 也要恢复 */
    // 重启传感器
    SENSOR_Reinit();
}

