// 1. 重复的 GPIO/ADC/SRAM 配置（DRY 原则违反）
// 2. 睡眠模式和唤醒源硬编码在函数里
// 3. 无法组合：BLE 需要 TIM2，传感器需要 BLE，但无法叠加
// 4. 唤醒后恢复代码 100% 重复

// === 重构后：策略模式——可组合的电源管理 ===

#include <stdint.h>
#include <stdbool.h>

/* 策略回调：每个场景实现自己的前置/后置动作 */
typedef struct power_strategy {
    const char *name;           /* 策略名称 */
    uint8_t max_sleep_depth;    /* 支持的最深睡眠模式 0-4 */
    void (*pre_enter)(void);    /* 进入前必须做的事 */
    void (*post_wakeup)(void);  /* 唤醒后必须做的事 */
    bool has_post_wakeup;       /* 是否有后置动作 */
} power_strategy_t;

/* 全局策略注册表 */
static power_strategy_t g_strategies[8];
static uint8_t g_strategy_count = 0;

/* 注册一个省电策略 */
int power_manager_register_strategy(power_strategy_t *strat)
{
    if (g_strategy_count >= 8) return -1;
    g_strategies[g_strategy_count++] = *strat;
    return 0;
}

/* 统一入口——所有场景都调这个 */
void power_manager_enter_sleep(uint8_t requested_depth)
{
    /* 找到支持的最深策略 */
    power_strategy_t *best = NULL;
    for (int i = 0; i < g_strategy_count; i++) {
        if (g_strategies[i].max_sleep_depth >= requested_depth) {
            best = &g_strategies[i];
            break;
        }
    }
    if (!best) return;  /* 没有合适的策略，保持唤醒 */

    /* 执行策略的前置动作 */
    if (best->pre_enter) best->pre_enter();

    /* 进入睡眠模式——策略决定用哪种 */
    switch (requested_depth) {
        case 0: HAL_PWR_EnterSLEEP_MODE(PWR_SLEEPENTRY_WFI); break;
        case 1: HAL_PWR_EnterDEEPSLEEP_MODE(); break;
        case 2: HAL_PWR_EnterSTOP2_MODE(); break;
    }
    // 不返回
}

/* 唤醒后恢复——调用所有有后置动作的策略 */
void power_manager_post_wakeup(void)
{
    for (int i = 0; i < g_strategy_count; i++) {
        if (g_strategies[i].has_post_wakeup &&
            g_strategies[i].post_wakeup) {
            g_strategies[i].post_wakeup();
        }
    }
}

/* === 场景实现：BLE 广播策略 === */
static void ble_pre_enter(void)
{
    __HAL_RCC_GPIOC_CLK_DISABLE();
    __HAL_RCC_ADC_CLK_DISABLE();
    HAL_PWREx_EnableSRAM2();
    __HAL_PWR_CLEAR_WUF_FLAG();
    // 配置 BLE 唤醒定时器
    HAL_RTCEx_SetWakeUpTimer_IT(&hrtc, 10000, RTC_WAKEUPCLOCK_RTCCLK_DIV16);
}

static void ble_post_wakeup(void)
{
    __HAL_RCC_GPIOC_CLK_ENABLE();
    __HAL_RCC_ADC_CLK_ENABLE();
    BLE_Reinit();
}

static power_strategy_t ble_strategy = {
    .name = "BLE_BROADCAST",
    .max_sleep_depth = 1,
    .pre_enter = ble_pre_enter,
    .post_wakeup = ble_post_wakeup,
    .has_post_wakeup = true
};

/* === 场景实现：传感器采样策略 === */
static void sensor_pre_enter(void)
{
    __HAL_RCC_GPIOC_CLK_DISABLE();
    __HAL_RCC_ADC_CLK_DISABLE();
    __HAL_RCC_TIM2_CLK_DISABLE();
    HAL_PWREx_EnableSRAM2();
    __HAL_PWR_CLEAR_WUF_FLAG();
    HAL_RTCEx_SetWakeUpTimer_IT(&hrtc, 1000, RTC_WAKEUPCLOCK_CK_SPRE_16BITS);
}

static void sensor_post_wakeup(void)
{
    __HAL_RCC_GPIOC_CLK_ENABLE();
    __HAL_RCC_ADC_CLK_ENABLE();
    __HAL_RCC_TIM2_CLK_ENABLE();
    SENSOR_Reinit();
}

static power_strategy_t sensor_strategy = {
    .name = "SENSOR_SAMPLE",
    .max_sleep_depth = 2,  /* STOP2，比 BLE 更深 */
    .pre_enter = sensor_pre_enter,
    .post_wakeup = sensor_post_wakeup,
    .has_post_wakeup = true
};

